import{_ as a,o as t,c as s,ai as i}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Net Drivers","description":"","frontmatter":{"title":"Net Drivers","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/net-drivers.md","filePath":"reference-manual/net-drivers.md"}'),n={name:"reference-manual/net-drivers.md"};function r(o,e,l,d,c,h){return t(),s("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/net-drivers.md for this page in Markdown format</div><h1 id="net-drivers" tabindex="-1">Net Drivers <a class="header-anchor" href="#net-drivers" aria-label="Permalink to “Net Drivers”">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>Every FPGA net in JZ-HDL is the culmination of declared signals, aliases, and directional connects. This page translates the Reference Manual’s driver model into practical rules, diagnostics, and patterns so you can safely describe buses, tri-state I/O, and combinational logic without tripping the compiler’s safety net.</p><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to “Key Concepts”">​</a></h2><h3 id="signals-nets-drivers" tabindex="-1">Signals, Nets, Drivers <a class="header-anchor" href="#signals-nets-drivers" aria-label="Permalink to “Signals, Nets, Drivers”">​</a></h3><table tabindex="0"><thead><tr><th>Term</th><th>What it represents</th></tr></thead><tbody><tr><td><strong>Signal</strong></td><td>A declared entity (<code>WIRE</code>, <code>REGISTER</code>, <code>PORT</code>) that names a storage or connectivity point.</td></tr><tr><td><strong>Net</strong></td><td>The combinational interconnect created after alias resolution. Multiple signals can collapse into the same net.</td></tr><tr><td><strong>Driver</strong></td><td>Any construct that actively assigns <code>0</code> or <code>1</code> to a net (register outputs, instance <code>OUT</code> ports, directional assignments, literals when allowed).</td></tr></tbody></table><h3 id="active-drivers-and-tri-state-behavior" tabindex="-1">Active Drivers and Tri-State Behavior <a class="header-anchor" href="#active-drivers-and-tri-state-behavior" aria-label="Permalink to “Active Drivers and Tri-State Behavior”">​</a></h3><p>Only determinate <code>0/1</code> values count toward the active driver budget; <code>z</code> is treated as “released” and ignored so tri-state buses can exist if exactly one driver is active when the net is read. The compiler tracks drivers flow-sensitively, so mutual exclusion and explicit <code>z</code> releases are required wherever more than one source may assert the same net.</p><h3 id="observability-and-x" tabindex="-1">Observability and <code>x</code> <a class="header-anchor" href="#observability-and-x" aria-label="Permalink to “Observability and x”">​</a></h3><p>The compiler forbids <code>x</code> bits from propagating into observable sinks (register resets, MEM inits, <code>OUT</code>/<code>INOUT</code> ports, top-level pins). Use structural masking (e.g., bitwise AND) to guarantee that any <code>x</code> is removed before a sink sees it; logical identities or “maybe x” reasoning is not tolerated.</p><h3 id="flow-sensitive-execution-paths" tabindex="-1">Flow-Sensitive Execution Paths <a class="header-anchor" href="#flow-sensitive-execution-paths" aria-label="Permalink to “Flow-Sensitive Execution Paths”">​</a></h3><p>Every net and register assignment is checked per execution path. A driver that is inactive on one path but active on another still counts toward the per-path limit, so your control structures must explicitly describe exclusion (e.g., <code>IF/ELSE</code>, <code>SELECT/CASE</code>, ternaries).</p><h2 id="building-nets-from-connections" tabindex="-1">Building Nets from Connections <a class="header-anchor" href="#building-nets-from-connections" aria-label="Permalink to “Building Nets from Connections”">​</a></h2><h3 id="aliasing-nets-with-z-s" tabindex="-1">Aliasing nets with <code>=</code>, <code>=z</code>, <code>=s</code> <a class="header-anchor" href="#aliasing-nets-with-z-s" aria-label="Permalink to “Aliasing nets with =, =z, =s”">​</a></h3><p>Alias operators merge signals into a single net. Aliasing is transitive—if <code>a = b</code> and <code>b = c</code>, then <code>a</code>, <code>b</code>, and <code>c</code> share one net. Width changes require <code>=z</code> or <code>=s</code> to show intent, and aliases inside <code>ASYNCHRONOUS</code> logic may not drive bare literals (use directional assignment for constants). After aliasing finishes, the compiler evaluates driver counts on each net bit.</p><h3 id="directional-connectors" tabindex="-1">Directional connectors (<code>=&gt;</code>, <code>&lt;=</code>) <a class="header-anchor" href="#directional-connectors" aria-label="Permalink to “Directional connectors (=&gt;, &lt;=)”">​</a></h3><p>Use <code>driver =&gt; sink;</code> (<code>=&gt;</code>) or <code>driver &lt;= sink;</code> (<code>&lt;=</code>) when you want to create a directed driver→sink relationship without merging nets. Directional connects keep the driver/source net separate while ensuring the sink sees the driver’s value. They are ideal when you need explicit arbitration (e.g., <code>a =&gt; b</code> for a registered output driving a bus) or when connecting combinational logic outputs without aliasing.</p><h3 id="constants-and-default-drivers" tabindex="-1">Constants and default drivers <a class="header-anchor" href="#constants-and-default-drivers" aria-label="Permalink to “Constants and default drivers”">​</a></h3><p>If a net is read anywhere, at least one driver must provide a known <code>0</code> or <code>1</code> value on every path. Nets with no active drivers but also no sinks are legal (e.g., dangling constants, debug hooks), but the compiler will flag a floating net if the net is observed. Provide defaults (a <code>DEFAULT</code> branch, explicit ternary, or a constant driver) to satisfy every path.</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Alias example: \`alias_net\` merges these signals</span></span>
<span class="line"><span>a = b;</span></span>
<span class="line"><span>c = a;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Directional driver relationship: no net merge</span></span>
<span class="line"><span>adder_out =&gt; result;</span></span></code></pre></div><h2 id="driver-exclusivity-and-flow-rules" tabindex="-1">Driver Exclusivity and Flow Rules <a class="header-anchor" href="#driver-exclusivity-and-flow-rules" aria-label="Permalink to “Driver Exclusivity and Flow Rules”">​</a></h2><h3 id="exclusive-assignment-rule-flow-sensitive" tabindex="-1">Exclusive Assignment Rule (Flow-sensitive) <a class="header-anchor" href="#exclusive-assignment-rule-flow-sensitive" aria-label="Permalink to “Exclusive Assignment Rule (Flow-sensitive)”">​</a></h3><p>Every assignable identifier (<code>REGISTER</code>, <code>WIRE</code>, <code>PORT</code>) must receive zero or one assignment per bit on every execution path through a block. Independent <code>IF</code> statements at the same nesting level both assigning the same signal violate this rule—even if they are mutually exclusive at runtime—because the compiler cannot assume holistically exclusive behavior unless it appears in the same control structure (<code>IF/ELSE/ELSEIF</code>, <code>SELECT/CASE</code>, ternary, etc.). Always restructure logic into exclusive branches or express the choice combinationally with a mux.</p><h3 id="registers-and-synchronous-updates" tabindex="-1">Registers and synchronous updates <a class="header-anchor" href="#registers-and-synchronous-updates" aria-label="Permalink to “Registers and synchronous updates”">​</a></h3><p>Registers expose two semantic roles:</p><ul><li><strong>Current-value output</strong>: readable in any block (acts as a driver).</li><li><strong>Next-state input</strong>: written only inside <code>SYNCHRONOUS</code> blocks.</li></ul><p>The Exclusive Assignment Rule applies to these next-state assignments, and register updates must remain within synchronous blocks (never inside <code>ASYNCHRONOUS</code>). Omitting an assignment on some paths simply keeps the previous value, supporting intended latch-like behavior without violating the rule.</p><h3 id="flow-sensitive-combinational-loop-detection" tabindex="-1">Flow-sensitive combinational loop detection <a class="header-anchor" href="#flow-sensitive-combinational-loop-detection" aria-label="Permalink to “Flow-sensitive combinational loop detection”">​</a></h3><p>The compiler builds a dependency graph of <code>ASYNCHRONOUS</code> assignments and flags cycles that can execute on the same path. True combinational loops (e.g., <code>a = b; b = a;</code>) are errors, but mutually exclusive cycles—where the loop can never be fully active on one run—are permitted (e.g., <code>IF (sel) { a = b; } ELSE { b = a; }</code>). Break problematic cycles by registering feedback or restructuring logic to eliminate simultaneous dependencies.</p><h2 id="tri-state-nets-and-inout-ports" tabindex="-1">Tri-State Nets and INOUT Ports <a class="header-anchor" href="#tri-state-nets-and-inout-ports" aria-label="Permalink to “Tri-State Nets and INOUT Ports”">​</a></h2><p><code>INOUT</code> ports and shared buses rely on tri-state arbitration. Each driver must release the net (<code>z</code>) whenever another driver could be active, and at least one driver has to drive a valid <code>0</code>/<code>1</code> when the net is actually sampled. The compiler enforces that no net is read while every driver is <code>z</code>, otherwise it reports a floating net.</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  data_bus = master_en ? master_data : 8&#39;bzzzz_zzzz;</span></span>
<span class="line"><span>  data_bus = slave_en  ? slave_data  : 8&#39;bzzzz_zzzz;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>// Compiler ensures master and slave cannot both drive at once.</span></span></code></pre></div><p>Use tri-state only when board-level buses require it; otherwise prefer muxed drivers so the Exclusive Assignment Rule is satisfied trivially.</p><h2 id="compiler-diagnostics-at-a-glance" tabindex="-1">Compiler Diagnostics at a Glance <a class="header-anchor" href="#compiler-diagnostics-at-a-glance" aria-label="Permalink to “Compiler Diagnostics at a Glance”">​</a></h2><p>The diagnostics below come from the net/tri-state and assignment rule sections of <code>jz-hdl/src/rules.c</code>. Their short names are the compiler’s rule IDs; the emitted message provides the exact reason.</p><table tabindex="0"><thead><tr><th>Diagnostic</th><th>What happened</th><th>How to fix it</th></tr></thead><tbody><tr><td><code>NET_FLOATING_WITH_SINK</code></td><td>A net has sinks (reads) but no active driver (or only <code>z</code>) on a given execution path.</td><td>Ensure every path drives the net with a determinate <code>0/1</code> value before it is read (default branch, constant driver, <code>DEFAULT</code>, etc.).</td></tr><tr><td><code>NET_TRI_STATE_ALL_Z_READ</code></td><td>Every driver puts the net into <code>z</code> by the time a read occurs, so the value is undefined.</td><td>Guarantee at least one driver remains active when the net is sampled, or enforce mutual exclusion around reads.</td></tr><tr><td><code>ASSIGN_MULTIPLE_SAME_BITS</code></td><td>The same identifier bits are assigned more than once along a single execution path.</td><td>Collapse the assignments into a single control structure (IF/ELSE/ELSEIF, SELECT/CASE, ternary) so each path writes once.</td></tr><tr><td><code>ASSIGN_INDEPENDENT_IF_SELECT</code></td><td>Independent IF/SELECT chains at the same level assign the same net, which the compiler treats as concurrent drivers.</td><td>Merge them into one control tree so exclusivity is explicit or move the conflicting assignment into a different net.</td></tr><tr><td><code>ASSIGN_SHADOWING</code></td><td>A parent-level assignment is followed by a nested assignment targeting overlapping bits (shadowing).</td><td>Restructure control flow to avoid overlapping assignments or refactor the nested logic.</td></tr><tr><td><code>ASYNC_ALIAS_LITERAL_RHS</code></td><td>An alias (<code>=</code>, <code>=z</code>, <code>=s</code>) inside <code>ASYNCHRONOUS</code> uses a bare literal RHS.</td><td>Drive the literal with <code>&lt;=/=&gt;</code> or introduce a dedicated source net instead.</td></tr><tr><td><code>OBS_X_TO_OBSERVABLE_SINK</code></td><td><code>x</code> bits can flow into observable sinks (register resets, MEM init, <code>OUT</code>/<code>INOUT</code>, top pins).</td><td>Mask or eliminate the <code>x</code> bits structurally; the compiler does not assume algebraic simplifications.</td></tr><tr><td><code>COMB_LOOP_UNCONDITIONAL</code></td><td>Flow-sensitive analysis found a combinational cycle that is active on the same path.</td><td>Break feedback using registers or restructure so the loop cannot be active on any path (mutually exclusive loops report <code>COMB_LOOP_CONDITIONAL_SAFE</code>).</td></tr></tbody></table><p>Additional flow-sensitive checks enforce one active driver per net bit (tri-state excepted), no floating nets, and alias-rules such as forbidding literals in <code>ASYNCHRONOUS</code> before aliasing.</p><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to “Best Practices”">​</a></h2><ul><li>Prefer directional connects (<code>=&gt;</code>, <code>&lt;=</code>) when you want controlled driver→sink relationships without aliasing.</li><li>Limit <code>=</code> to intentional net aliasing; double-check width changes and avoid aliasing literals inside <code>ASYNCHRONOUS</code>.</li><li>Collapse multiple assignments to one structure (<code>IF/ELSE</code>, <code>SELECT/CASE</code>, ternary) to satisfy the Exclusive Assignment Rule.</li><li>Keep combinational paths acyclic by passing feedback through registers.</li><li>Use tri-state drivers only for real shared buses; otherwise implement arbitration with muxes or explicit enable signals.</li><li>Mask any literal <code>x</code> bits before they reach observable outputs.</li><li>Document arbitration assumptions so the compiler can prove mutual exclusion.</li></ul><h2 id="author-checklist" tabindex="-1">Author Checklist <a class="header-anchor" href="#author-checklist" aria-label="Permalink to “Author Checklist”">​</a></h2><ul><li>[ ] Every read net has at least one driver supplying <code>0</code>/<code>1</code> on all paths.</li><li>[ ] No two drivers can be active on the same path for the same bit (unless tri-state <code>z</code> releases prove safety).</li><li>[ ] <code>=</code> aliases are intentional; replace with directional connectors unless a merged net is required.</li><li>[ ] ASYNCHRONOUS aliases never target bare literals; use directional constants instead.</li><li>[ ] Combinational dependencies form an acyclic graph on each execution path.</li><li>[ ] No <code>x</code> bits reach registers, MEM init, ports, or pins without masking.</li><li>[ ] Tri-state drivers are mutually exclusive or ensure a single active driver during reads.</li></ul><h2 id="pattern-examples" tabindex="-1">Pattern Examples <a class="header-anchor" href="#pattern-examples" aria-label="Permalink to “Pattern Examples”">​</a></h2><h3 id="safe-muxed-assignment" tabindex="-1">Safe muxed assignment <a class="header-anchor" href="#safe-muxed-assignment" aria-label="Permalink to “Safe muxed assignment”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  out = sel ? data1 : data0;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Single driver, deterministic on every path.</p><h3 id="independent-ifs-invalid" tabindex="-1">Independent IFs (invalid) <a class="header-anchor" href="#independent-ifs-invalid" aria-label="Permalink to “Independent IFs (invalid)”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  IF (a) { sig = x; }</span></span>
<span class="line"><span>  IF (b) { sig = y; }  // ERROR: two paths assign \`sig\` separately</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="registered-feedback-to-break-loops" tabindex="-1">Registered feedback to break loops <a class="header-anchor" href="#registered-feedback-to-break-loops" aria-label="Permalink to “Registered feedback to break loops”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>REGISTER { state [8] = 8&#39;h00; }</span></span>
<span class="line"><span>SYNCHRONOUS(CLK=clk) {</span></span>
<span class="line"><span>  state = next_state;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  next_state = f(input, state);  // \`state\` is registered—no combinational loop</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="tri-state-bus-with-explicit-releases" tabindex="-1">Tri-state bus with explicit releases <a class="header-anchor" href="#tri-state-bus-with-explicit-releases" aria-label="Permalink to “Tri-state bus with explicit releases”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  data_bus = master_en ? master_data : 8&#39;bzzzz_zzzz;</span></span>
<span class="line"><span>  data_bus = slave_en  ? slave_data  : 8&#39;bzzzz_zzzz;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Guarantee <code>master_en</code> and <code>slave_en</code> can never be high simultaneously to avoid <code>MULTIPLE_ACTIVE_DRIVERS</code>.</p>`,53)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
